-- FISCARA — FCRA Detail (15 USC §§ 1681)
-- ═══════════════════════════════════════════════════════════════════════════

-- FCRA Permissible Purpose
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_034', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC § 1681b (Fair Credit Reporting Act — Permissible Purposes)', 'FCRA § 1681b', 'FCRA Permissible Purpose — Conditions for Obtaining Consumer Reports', 'Restricts who may obtain consumer reports and under what circumstances. A consumer reporting agency may furnish a report only for enumerated permissible purposes: credit transactions, employment screening (with consumer consent), insurance underwriting, legitimate business transactions initiated by consumer, government licensing, and court orders. Obtaining a report without permissible purpose is a federal violation with civil liability.', '["Consumer report may only be furnished for permissible purpose","Credit transaction: written instructions of consumer or credit/insurance/employment evaluation","Employment purpose requires clear written disclosure and consumer authorization BEFORE procurement","Insurance underwriting: connection with underwriting of insurance involving consumer","Legitimate business transaction initiated by consumer","Court order or federal grand jury subpoena","Account review: existing credit relationship for account monitoring","Prescreened offers: firm offer of credit or insurance","Government licensing or benefits determination","No permissible purpose for general curiosity or litigation research without court order"]', '[{"section":"1681b(a)","description":"Enumerated permissible purposes for furnishing consumer reports"},{"section":"1681b(a)(2)","description":"Written instructions of consumer"},{"section":"1681b(a)(3)(A)","description":"Credit transaction — intends to use in connection with credit"},{"section":"1681b(a)(3)(B)","description":"Employment purposes — with consumer consent"},{"section":"1681b(a)(3)(C)","description":"Insurance underwriting purpose"},{"section":"1681b(a)(3)(F)","description":"Legitimate business transaction initiated by consumer"},{"section":"1681b(b)","description":"Conditions for furnishing reports for employment purposes"},{"section":"1681b(c)","description":"Furnishing reports for prescreened offers"},{"section":"1681b(f)","description":"Prohibition on obtaining report under false pretenses"}]', '["credit_application","employment_authorization","consumer_report","prescreened_offer","insurance_application","court_order"]', '["banking-financial-document-audit"]', 'CFPB / FTC', 1, 1, datetime('now'), datetime('now'));

-- FCRA Consumer Disclosure Rights
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_035', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC § 1681g (Fair Credit Reporting Act — Consumer Disclosures)', 'FCRA § 1681g', 'FCRA Consumer Disclosure Rights — Right to Know File Contents', 'Every consumer reporting agency must, upon request, clearly and accurately disclose to the consumer all information in the consumer''s file, sources of information, identification of each person who procured a report in the preceding year (two years for employment), and the consumer''s credit score. Free annual disclosure under § 1681j. Consumer has right to know what is being reported about them.', '["CRA must disclose all information in consumer file upon request","Must identify sources of information in file","Must disclose all inquiries — identity of each person procuring report in past year","Employment inquiries disclosed for past 2 years","Must disclose credit score and key factors","Must provide free annual file disclosure (AnnualCreditReport.com) per § 1681j","Disclosure must be clear, accurate, and in understandable form","Must disclose any risk score or predictor used","Must provide summary of rights with each disclosure","Must provide trained personnel to explain disclosure"]', '[{"section":"1681g(a)(1)","description":"Disclosure of all information in consumer file"},{"section":"1681g(a)(2)","description":"Sources of information disclosed"},{"section":"1681g(a)(3)","description":"Identity of inquirers — past year (2 years employment)"},{"section":"1681g(a)(5)","description":"Identification of inquiries for prescreened offers"},{"section":"1681g(f)","description":"Disclosure of credit scores"},{"section":"1681g(c)","description":"Summary of consumer rights must accompany disclosure"},{"section":"1681j(a)","description":"Free annual disclosure — one per 12-month period from each CRA"},{"section":"1681j(b)","description":"Free disclosure upon adverse action, fraud alert, unemployment, public assistance"}]', '["credit_report","file_disclosure","annual_credit_report","credit_score_disclosure","adverse_action_notice","consumer_rights_summary"]', '["banking-financial-document-audit"]', 'CFPB / FTC', 1, 1, datetime('now'), datetime('now'));

-- FCRA Dispute Procedures
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_036', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC § 1681i (Fair Credit Reporting Act — Dispute Procedures)', 'FCRA § 1681i', 'FCRA Dispute Procedures — Reinvestigation of Disputed Information', 'When a consumer disputes the completeness or accuracy of any item in their file, the CRA must conduct a reasonable reinvestigation within 30 days (extendable to 45 if consumer provides additional info). CRA must forward all relevant information to the furnisher within 5 business days. If information cannot be verified, it must be deleted. Consumer must be notified of results within 5 business days of completion.', '["Consumer may dispute any item in file as inaccurate or incomplete","CRA must conduct reasonable reinvestigation within 30 days","30-day period may extend to 45 days if consumer provides additional information during investigation","CRA must forward dispute and all relevant information to furnisher within 5 business days","If disputed information cannot be verified, CRA must promptly delete or modify","CRA must provide written results to consumer within 5 business days of completion","If reinvestigation does not resolve dispute, consumer may file statement of dispute (100 words)","CRA must note item is disputed in subsequent reports","Frivolous disputes may be rejected with notice to consumer within 5 days","Consumer may request that revised report be sent to recent recipients"]', '[{"section":"1681i(a)(1)","description":"Reinvestigation required within 30 days"},{"section":"1681i(a)(2)","description":"Forward dispute to furnisher within 5 business days"},{"section":"1681i(a)(3)","description":"Determination and recording — delete if unverified"},{"section":"1681i(a)(5)","description":"45-day extension when consumer provides additional information"},{"section":"1681i(a)(6)","description":"Notice of results to consumer within 5 business days"},{"section":"1681i(b)","description":"Consumer statement of dispute — 100 words"},{"section":"1681i(c)","description":"Notification of dispute to recent report recipients"},{"section":"1681i(d)","description":"Notification of deletion to recipients at consumer request"}]', '["credit_dispute_letter","reinvestigation_notice","dispute_results_notice","consumer_statement_of_dispute","furnisher_response","deletion_notice"]', '["banking-financial-document-audit"]', 'CFPB / FTC', 1, 1, datetime('now'), datetime('now'));

-- FCRA Duties of Furnishers
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_037', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC § 1681s-2 (Fair Credit Reporting Act — Duties of Furnishers)', 'FCRA § 1681s-2', 'FCRA Duties of Furnishers of Information — Accuracy and Dispute Obligations', 'Imposes duties on persons who furnish information to consumer reporting agencies. Section (a) requires accuracy — no reporting of information known to be inaccurate. Section (b) creates duties upon notice of dispute from CRA: must investigate, review all relevant information, report results, and correct inaccurate information. Section (b) provides private right of action; section (a) is enforced only by regulators.', '["Must not furnish information known to be inaccurate (§ 1681s-2(a))","Must correct and update information previously reported that is incomplete or inaccurate","Must provide notice to CRA when consumer disputes directly to furnisher","Upon notice of dispute from CRA, must conduct investigation within 30 days","Must review all relevant information provided by CRA with dispute","Must report results of investigation to CRA","Must modify, delete, or permanently block reporting if inaccurate","Must not re-report information that was previously deleted as inaccurate","Must notify consumer if account information reported as disputed","Reasonable procedures to ensure maximum possible accuracy"]', '[{"section":"1681s-2(a)(1)","description":"Duty to provide accurate information — no knowing inaccuracies"},{"section":"1681s-2(a)(2)","description":"Duty to correct and update previously furnished information"},{"section":"1681s-2(a)(3)","description":"Duty not to report information with notice of dispute from consumer"},{"section":"1681s-2(a)(8)","description":"Duty to provide notice of negative information to consumer"},{"section":"1681s-2(b)(1)","description":"Investigation duties upon notice of dispute from CRA"},{"section":"1681s-2(b)(1)(B)","description":"Review all relevant information from CRA"},{"section":"1681s-2(b)(1)(C)","description":"Report results of investigation to CRA"},{"section":"1681s-2(b)(1)(D)","description":"Modify, delete, or block if found inaccurate"},{"section":"1681s-2(b)(1)(E)","description":"Notify all CRAs if information found inaccurate"}]', '["furnisher_dispute_response","ACDV_response","correction_notice","negative_information_notice","investigation_results","data_furnishing_agreement"]', '["banking-financial-document-audit"]', 'CFPB / FTC / State AG', 1, 1, datetime('now'), datetime('now'));

-- FCRA Identity Theft Provisions
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_038', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC §§ 1681c-1, 1681c-2 (Fair Credit Reporting Act — Identity Theft Protections)', 'FCRA §§ 1681c-1/1681c-2', 'FCRA Identity Theft Provisions — Fraud Alerts and Blocks', 'Provides identity theft victims with tools to protect credit files. Initial fraud alert (1 year) requires only good faith suspicion; extended alert (7 years) requires identity theft report. Active duty military alert for deployed servicemembers. CRA must block reporting of information resulting from identity theft upon submission of identity theft report. Truncation of SSN required on consumer disclosures.', '["Initial fraud alert: 1 year, good faith suspicion of identity theft","Extended fraud alert: 7 years, requires identity theft report (police report or FTC affidavit)","Active duty military alert: 1 year for deployed servicemembers","CRA receiving alert must notify other two nationwide CRAs within 1 business day","Creditor must take reasonable steps to verify identity before extending credit during alert","Consumer may request free credit report upon placing fraud alert","Block of information resulting from identity theft upon identity theft report","CRA must block within 4 business days of receiving documentation","Furnisher notified of block and may not re-report blocked information","CRA must not include blocked information in subsequent reports"]', '[{"section":"1681c-1(a)","description":"Initial fraud alert — 1 year upon good faith suspicion"},{"section":"1681c-1(b)","description":"Extended fraud alert — 7 years with identity theft report"},{"section":"1681c-1(c)","description":"Active duty military alert"},{"section":"1681c-1(d)","description":"Procedures — CRA must notify other nationwide CRAs within 1 day"},{"section":"1681c-1(h)","description":"Free credit report upon placing fraud alert"},{"section":"1681c-2(a)","description":"Block of information resulting from identity theft"},{"section":"1681c-2(b)","description":"4 business day block requirement after documentation received"},{"section":"1681c-2(c)","description":"Notification to furnisher of block"},{"section":"1681c-2(d)","description":"Furnisher may not re-report blocked information"}]', '["fraud_alert_request","identity_theft_report","FTC_identity_theft_affidavit","police_report","block_request","credit_freeze_request","active_duty_alert"]', '["banking-financial-document-audit"]', 'CFPB / FTC', 1, 1, datetime('now'), datetime('now'));

-- FCRA Civil Liability
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_039', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC §§ 1681n, 1681o (Fair Credit Reporting Act — Civil Liability)', 'FCRA §§ 1681n/1681o', 'FCRA Civil Liability — Willful and Negligent Noncompliance', 'Establishes private right of action for FCRA violations. Willful noncompliance (§ 1681n): actual damages or statutory damages ($100-$1,000 per violation), plus punitive damages, plus attorney fees. Negligent noncompliance (§ 1681o): actual damages plus attorney fees. Two-year statute of limitations from discovery, maximum five years from violation. Class actions permitted for willful violations.', '["Willful noncompliance: actual damages or statutory damages $100-$1,000","Willful noncompliance: punitive damages available","Willful noncompliance: reasonable attorney fees and costs","Negligent noncompliance: actual damages only","Negligent noncompliance: reasonable attorney fees and costs","Statute of limitations: 2 years from discovery of violation","Absolute statute of repose: 5 years from date of violation","Class actions permitted under § 1681n (willful)","Obtaining consumer report under false pretenses: criminal liability up to $5,000 fine and 1 year imprisonment","Unauthorized disclosure by CRA officer: criminal liability"]', '[{"section":"1681n(a)(1)(A)","description":"Willful noncompliance — actual damages"},{"section":"1681n(a)(1)(B)","description":"Willful noncompliance — statutory damages $100-$1,000"},{"section":"1681n(a)(2)","description":"Punitive damages for willful noncompliance"},{"section":"1681n(a)(3)","description":"Attorney fees and costs for willful noncompliance"},{"section":"1681o(a)","description":"Negligent noncompliance — actual damages and attorney fees"},{"section":"1681p","description":"Jurisdiction — federal district court, no amount in controversy"},{"section":"1681q","description":"Criminal liability — obtaining report under false pretenses"},{"section":"1681r","description":"Criminal liability — unauthorized disclosure by CRA officer"}]', '["FCRA_complaint","civil_complaint","class_action_complaint","damages_calculation","attorney_fee_petition","demand_letter"]', '["banking-financial-document-audit"]', 'Federal District Court / CFPB', 1, 1, datetime('now'), datetime('now'));


