-- BSA/AML Reporting
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_058', 'FISCARA', 'FEDERAL_STATUTE', 'US', '31 USC §§ 5311-5332 (Bank Secrecy Act / Anti-Money Laundering)', 'BSA §§ 5311-5332', 'Bank Secrecy Act / Anti-Money Laundering — CTR and SAR Reporting', 'Requires financial institutions to assist government agencies in detecting and preventing money laundering. Currency Transaction Reports (CTR) required for cash transactions over $10,000. Suspicious Activity Reports (SAR) required when institution suspects transaction involves funds from illegal activity or is designed to evade BSA requirements. Structuring transactions to avoid CTR threshold (smurfing) is a federal crime. FinCEN administers BSA.', '["Currency Transaction Report (CTR) required for cash transactions over $10,000","CTR must be filed within 15 calendar days of transaction","Suspicious Activity Report (SAR) required for transactions suspected of involving illegal funds","SAR must be filed within 30 calendar days of detection (60 days if no suspect identified)","SAR filing is confidential — institution may not notify subject of SAR","Structuring: breaking transactions to avoid $10,000 CTR threshold is federal crime","Customer Identification Program (CIP) required — verify identity of account holders","Customer Due Diligence (CDD) rule: identify and verify beneficial owners (25%+ ownership)","Record retention: 5 years for CTRs, SARs, and CDD records","Anti-money laundering (AML) compliance program required: internal controls, compliance officer, training, independent testing","Penalties: civil up to $1M per violation; criminal up to $500K fine and 10 years imprisonment"]', '[{"section":"5313","description":"Currency Transaction Reports — cash transactions over $10,000"},{"section":"5318(g)","description":"Suspicious Activity Reports — transactions involving suspected illegal funds"},{"section":"5318(h)","description":"AML compliance program requirements"},{"section":"5318(l)","description":"Customer Identification Program (CIP)"},{"section":"5324","description":"Structuring prohibition — circumventing CTR requirements"},{"section":"5321","description":"Civil penalties — up to $1M per violation"},{"section":"5322","description":"Criminal penalties — up to $500K and 10 years"},{"section":"5332","description":"Bulk cash smuggling — transporting over $10,000 undeclared"},{"section":"31 CFR 1010.230","description":"Beneficial ownership / CDD rule — 25% ownership threshold"},{"section":"31 CFR 1020.320","description":"SAR filing requirements and timeframes"}]', '["CTR_report","SAR_report","CIP_documentation","CDD_beneficial_ownership","AML_compliance_program","transaction_monitoring_alert","suspicious_transaction_report"]', '["banking-financial-document-audit"]', 'FinCEN / OCC / FDIC / Federal Reserve / DOJ', 0, 1, datetime('now'), datetime('now'));

-- Escheat/Unclaimed Property
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_059', 'FISCARA', 'STATE_STATUTE', 'CA', 'Cal. Code Civ. Proc. §§ 1500-1599 (Unclaimed Property Law)', 'CCP §§ 1500-1599', 'California Unclaimed Property Law — Escheat and Holder Obligations', 'Requires holders of unclaimed property (banks, corporations, insurers, government entities) to report and deliver unclaimed property to the California State Controller after specified dormancy periods. Bank accounts dormant 3 years, uncashed checks 3 years, wages 1 year, safe deposit boxes 3 years. Holder must send due diligence notice to owner before reporting. Owner may claim property from Controller at any time — no statute of limitations.', '["Bank accounts: 3-year dormancy period","Uncashed checks and money orders: 3 years","Wages and payroll: 1 year","Safe deposit box contents: 3 years","Insurance proceeds: 3 years from due date","Holder must send written due diligence notice to last known address 6-12 months before reporting","Report filed annually with State Controller by November 1","Holder must deliver property to Controller with report","Controller publishes notice of unclaimed property","Owner may claim property from Controller at any time — no time limit","Holder immune from liability after delivery to Controller","Penalties for failure to report: 12% per annum interest + $100-$500 per day","Controller may examine holder records"]', '[{"section":"1510","description":"General dormancy period — 3 years for most property"},{"section":"1513","description":"Bank deposits and funds — 3-year dormancy"},{"section":"1514","description":"Uncashed checks and outstanding drafts — 3 years"},{"section":"1516","description":"Insurance proceeds — 3 years"},{"section":"1519","description":"Safe deposit box contents — 3 years"},{"section":"1520","description":"Wages, commissions, and other compensation — 1 year"},{"section":"1530","description":"Holder report to Controller — annual by November 1"},{"section":"1531","description":"Due diligence notice — 6-12 months before report date"},{"section":"1540","description":"Owner claim from Controller — no time limit"},{"section":"1577","description":"Controller authority to examine holder records"},{"section":"1576","description":"Penalties for failure to report"}]', '["unclaimed_property_report","due_diligence_notice","owner_claim_form","dormancy_review","Controller_audit_notice","holder_compliance_report"]', '["banking-financial-document-audit"]', 'California State Controller''s Office', 0, 1, datetime('now'), datetime('now'));

-- CA Homeowner Bill of Rights
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_060', 'FISCARA', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 2920.5-2944.7 (California Homeowner Bill of Rights)', 'CC §§ 2920.5-2944.7', 'California Homeowner Bill of Rights — Foreclosure Protections', 'Provides comprehensive foreclosure protections for California homeowners. Prohibits dual tracking — servicer cannot advance foreclosure while borrower has pending loan modification application. Requires single point of contact for borrowers in default. Guarantees right to appeal loan modification denial. Prohibits recording Notice of Default until 30 days after initial contact or due diligence. Material violations provide injunctive relief before sale; after sale, treble actual damages.', '["Prohibition on dual tracking — cannot record NOD or NTS while complete loan modification application pending","Single point of contact required for borrowers in default","Right to appeal loan modification denial","Servicer must contact borrower 30 days before recording NOD to explore alternatives","Must assess borrower for all available loss mitigation options","Cannot record NOD until 30 days after initial contact or due diligence requirements met","Written determination on loan modification within 30 days of receiving complete application","If approved for trial modification, permanent modification must be offered if trial completed","Must provide written notice of denial with specific reasons","Borrower may appeal denial — servicer must respond within 15 days","Before sale: injunctive relief available for material violation","After sale: treble actual damages for material violation"]', '[{"section":"2923.4","description":"Material compliance standard"},{"section":"2923.5","description":"Pre-NOD contact requirement — 30 days before recording"},{"section":"2923.55","description":"Due diligence before NOD — letter with loss mitigation options"},{"section":"2923.6","description":"Prohibition on dual tracking — no foreclosure during modification review"},{"section":"2923.6(d)","description":"Right to appeal loan modification denial"},{"section":"2923.7","description":"Single point of contact requirement"},{"section":"2924.9","description":"Written notice of foreclosure prevention alternatives"},{"section":"2924.10","description":"Acknowledgment of loan modification documents within 5 business days"},{"section":"2924.11","description":"Prohibition on recording NTS while modification under review"},{"section":"2924.12","description":"Enforcement — injunctive relief before sale, treble damages after sale"},{"section":"2924.17","description":"Declaration of compliance required with NOD and NTS"}]', '["Notice_of_Default","Notice_of_Trustee_Sale","loan_modification_application","single_point_of_contact_notice","modification_denial","modification_appeal","forbearance_agreement","declaration_of_compliance"]', '["banking-financial-document-audit"]', 'California Superior Court / DFPI / CA AG', 1, 1, datetime('now'), datetime('now'));

-- Servicemembers Civil Relief Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_061', 'FISCARA', 'FEDERAL_STATUTE', 'US', '50 USC §§ 3901-4043 (Servicemembers Civil Relief Act)', 'SCRA §§ 3901-4043', 'Servicemembers Civil Relief Act — Financial Protections for Military', 'Provides comprehensive financial protections for active duty servicemembers, including 6% interest rate cap on pre-service debts, protection from default judgments, stay of proceedings, protection from non-judicial foreclosure, and limits on repossession. Covers all active duty military, National Guard/Reserve on federal active duty, and in some provisions dependents. Protections generally apply from date of active duty orders through period of military service plus applicable post-service lookback.', '["6% interest rate cap on pre-service obligations — including mortgages, credit cards, auto loans","Creditor must forgive interest exceeding 6% — not defer","Protection from default judgment — court must appoint attorney before entry","Stay of civil proceedings — court must grant upon request if service materially affects ability","No non-judicial foreclosure during service and 12 months after (extended from 9 months)","No repossession of property without court order during service","Lease termination right: may terminate residential or vehicle lease upon deployment or PCS","Protection of life insurance: SGLI coverage, no lapse during service","No penalties or adverse credit reporting for exercising SCRA rights","Servicemember must provide written notice and copy of military orders to invoke protections","DOJ may bring civil action for pattern or practice violations","Private right of action with actual damages, declaratory and injunctive relief"]', '[{"section":"3937","description":"Maximum rate of interest — 6% on pre-service obligations"},{"section":"3931","description":"Protection against default judgments — attorney appointment"},{"section":"3932","description":"Stay of proceedings upon application"},{"section":"3953","description":"Mortgage foreclosure protection — no non-judicial foreclosure during service + 12 months"},{"section":"3952","description":"No installment contract repossession without court order"},{"section":"3955","description":"Residential and vehicle lease termination right"},{"section":"3956","description":"Cell phone contract termination right"},{"section":"3958","description":"Professional liability protection — malpractice insurance tolling"},{"section":"3998","description":"Fine up to $55,000 for first violation, $110,000 for subsequent"},{"section":"4042","description":"Private right of action — actual damages, declaratory and injunctive relief"}]', '["military_orders","SCRA_interest_rate_request","lease_termination_notice","stay_of_proceedings_motion","foreclosure_protection_notice","default_judgment_affidavit","DOJ_complaint"]', '["banking-financial-document-audit"]', 'DOJ / Federal District Court', 1, 1, datetime('now'), datetime('now'));
